const AWS = require('aws-sdk');
const { exec } = require('child_process');
const path = require('path');
const fs = require('fs');

const s3 = new AWS.S3();
const tmpDir = '/tmp';

exports.handler = async (event) => {
    try {
        const record = event.Records[0];
        const bucket = record.s3.bucket.name;
        const key = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
        const outputFormat = record.s3.object.metadata.outputFormat;

        const inputFilePath = path.join(tmpDir, key.split('/').pop());
        const outputFilePath = path.join(tmpDir, `${path.basename(key, path.extname(key))}.${outputFormat}`);

        await downloadImage(bucket, key, inputFilePath);
        await convertImage(inputFilePath, outputFilePath);
        await uploadImage(bucket, outputFilePath, `${path.basename(key, path.extname(key))}.${outputFormat}`);

        fs.unlinkSync(inputFilePath);
        fs.unlinkSync(outputFilePath);

        return { status: 'Image processed successfully' };
    } catch (error) {
        console.error(error);
        throw new Error('Image processing failed');
    }
};

const downloadImage = (bucket, key, outputPath) => {
    return new Promise((resolve, reject) => {
        const params = { Bucket: bucket, Key: key };
        const file = fs.createWriteStream(outputPath);
        s3.getObject(params).createReadStream().pipe(file)
            .on('finish', resolve)
            .on('error', reject);
    });
};

const convertImage = (inputPath, outputPath) => {
    return new Promise((resolve, reject) => {
        exec(`convert ${inputPath} ${outputPath}`, (error) => {
            if (error) {
                return reject(error);
            }
            resolve();
        });
    });
};

const uploadImage = (bucket, filePath, key) => {
    return new Promise((resolve, reject) => {
        const fileContent = fs.readFileSync(filePath);
        const params = {
            Bucket: bucket,
            Key: key,
            Body: fileContent,
            ContentType: `image/${path.extname(key).slice(1)}`,
        };
        s3.upload(params, (error) => {
            if (error) {
                return reject(error);
            }
            resolve();
        });
    });
};